const payload = $json.body ?? $json;
const tasks = Array.isArray(payload.tasks) ? payload.tasks : [];
const petIntimacy = Number(payload.pet_intimacy ?? payload.app_context?.pet?.intimacy ?? 0);
const normalize = (task) => ({
  task_id: task.id,
  title: task.title ?? '今日小任务',
  reward_points: Number(task.reward_points ?? task.rewardPoints ?? 0),
  current_progress: Number(task.current_progress ?? task.currentProgress ?? 0),
  total_progress: Number(task.total_progress ?? task.totalProgress ?? 1),
  is_completed: Boolean(task.is_completed ?? task.isCompleted),
  is_claimable: Boolean(task.is_claimable ?? task.isClaimable),
  type: task.type ?? 'daily'
});
let candidates = tasks.map(normalize).filter((task) => !task.is_completed);
candidates.sort((a, b) => {
  if (a.is_claimable !== b.is_claimable) return a.is_claimable ? -1 : 1;
  const ap = a.current_progress / Math.max(a.total_progress, 1);
  const bp = b.current_progress / Math.max(b.total_progress, 1);
  return bp - ap || b.reward_points - a.reward_points;
});
if (candidates.length === 0) {
  candidates = [
    { task_id: 'check_pet', title: '和小 emo 互动一次', reward_points: 10, current_progress: 0, total_progress: 1, is_claimable: false, type: 'pet' },
    { task_id: 'view_project', title: '查看一个应援项目', reward_points: 8, current_progress: 0, total_progress: 1, is_claimable: false, type: 'crowdfunding' },
    { task_id: 'save_memory', title: '记录一条今天的回忆', reward_points: 12, current_progress: 0, total_progress: 1, is_claimable: false, type: 'memory' }
  ];
}
const recommendedTasks = candidates.slice(0, 3).map((task, index) => ({
  task_id: task.task_id,
  title: task.title,
  priority: index === 0 ? 'high' : 'medium',
  reason: task.is_claimable ? '奖励已经可领取，先收下最稳。' : (task.current_progress > 0 ? '已经有进度，继续完成成本更低。' : '适合作为今天的轻量启动任务。')
}));
const petSuggestion = petIntimacy < 60 ? '亲密度偏低，今天可以先做一次宠物互动。' : '亲密度状态不错，任务节奏可以轻一点。';
return [{ json: { skill_id: 'fan.daily_task_planner.v1', status: 'ok', summary: '已整理今日任务优先级。', recommended_tasks: recommendedTasks, pet_suggestion: petSuggestion, next_actions: [{ type: 'navigate', label: '打开今日任务', route: '/pet/task' }], received: payload } }];
